module accu
(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output reg valid_out,
    output reg [9:0] data_out
);

reg [2:0] cnt;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 3'b0;
        valid_out <= 1'b0;
        data_out <= 10'b0;
    end else begin
        if (valid_in) begin
            if (cnt == 3'd3) begin
                cnt <= 3'b0;
                valid_out <= 1'b1;
                data_out <= data_out + data_in;
            end else begin
                cnt <= cnt + 1;
                valid_out <= 1'b0;
                data_out <= data_out + data_in;
            end
        end else begin
            if (cnt == 3'd3) begin
                cnt <= 3'b0;
                valid_out <= 1'b1;
                data_out <= data_out;
            end else begin
                cnt <= cnt;
                valid_out <= 1'b0;
                data_out <= data_out;
            end
        end
    end
end

endmodule
